class Solution {
public:
    bool canConvertString(string s, string t, int k) {
        if (s.size() != t.size()) return false;
        int cnt[26] = {0};
        for (int i = 0; i < s.size(); ++i) {
            int diff = (t[i] - s[i] + 26) % 26;
            if (diff) cnt[diff]++;
        }
        for (int d = 1; d < 26; ++d) {
            if (cnt[d] == 0) continue;
            int max_step = d + 26 * (cnt[d] - 1);
            if (max_step > k) return false;
        }
        return true;
    }
};
```
